import {
  ref,
  set,
  get,
  onValue,
  update,
  remove
} from "firebase/database";

import { db } from "./firebaseConfig";

/* =========================
   CHORE POINTS CONFIG
========================= */
export const CHORE_POINTS = {
  "Wash Dishes": 10,
  "Clean Bathroom": 25,
  "Take Out Trash": 15,
  "Vacuum Living Room": 20,
  "Laundry": 30
};

/* =========================
   USERS
========================= */

// Add user
export const addUser = async (name) => {
  const userRef = ref(db, `users/${Date.now()}`);

  const user = {
    name,
    totalPoints: 0,
    taskCount: 0
  };

  await set(userRef, user);

  return { uid: userRef.key, ...user };
};

// Get all users
export const getUsers = async () => {
  const snap = await get(ref(db, "users"));
  const data = snap.val() || {};

  return Object.entries(data).map(([uid, value]) => ({
    uid,
    ...value
  }));
};

/* =========================
   TASKS (WITH DUE DATE SUPPORT)
========================= */

// Add task
export const addTask = async (task) => {
  const taskRef = ref(db, `tasks/${Date.now()}`);

  const points =
    task.customPoints ||
    CHORE_POINTS[task.title] ||
    10;

  await set(taskRef, {
    ...task,
    points,
    status: "pending",
    createdAt: Date.now(),
    dueDate: task.dueDate || null   // ✅ IMPORTANT
  });

  return { success: true, points };
};

// Complete task
export const completeTask = async (taskId, userId, userName) => {
  const taskRef = ref(db, `tasks/${taskId}`);
  const userRef = ref(db, `users/${userId}`);

  const taskSnap = await get(taskRef);
  if (!taskSnap.exists()) {
    return { success: false, message: "Task not found" };
  }

  const task = taskSnap.val();

  // update user points
  const userSnap = await get(userRef);
  const user = userSnap.val();

  const newPoints = (user.totalPoints || 0) + (task.points || 0);
  const newCount = (user.taskCount || 0) + 1;

  await update(userRef, {
    totalPoints: newPoints,
    taskCount: newCount
  });

  // mark task completed
  await update(taskRef, {
    status: "completed",
    completedAt: Date.now(),
    completedName: userName
  });

  return {
    success: true,
    pointsAwarded: task.points || 0
  };
};

// Update task
export const updateTask = async (taskId, updates) => {
  const taskRef = ref(db, `tasks/${taskId}`);
  await update(taskRef, updates);
};

// Delete task
export const deleteTask = async (taskId) => {
  const taskRef = ref(db, `tasks/${taskId}`);
  await remove(taskRef);
};

/* =========================
   RESET (OPTIONAL TEST)
========================= */
export const resetAllScores = async () => {
  await remove(ref(db, "users"));
  await remove(ref(db, "tasks"));
};
